'use client'
import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { showToast } from '@/components/ui/Toast'
import BuildOnSelector from '@/components/projects/BuildOnSelector'
import type { Tag } from '@/lib/types/database'

const SEMESTERS = ['1st Sem','2nd Sem','3rd Sem','4th Sem','5th Sem','6th Sem','7th Sem','8th Sem']
const YEARS = ['2020-21','2021-22','2022-23','2023-24','2024-25','2025-26']

export default function SubmitProjectPage() {
  const [tags, setTags]         = useState<Tag[]>([])
  const [loading, setLoading]   = useState(false)
  const [userId, setUserId]     = useState<string | null>(null)

  // Form fields
  const [title, setTitle]           = useState('')
  const [description, setDesc]      = useState('')
  const [longDesc, setLongDesc]     = useState('')
  const [repoUrl, setRepoUrl]       = useState('')
  const [liveUrl, setLiveUrl]       = useState('')
  const [demoUrl, setDemoUrl]       = useState('')
  const [semester, setSemester]     = useState('')
  const [year, setYear]             = useState('')
  const [selectedTags, setSelTags]  = useState<string[]>([])
  const [buildOns, setBuildOns]     = useState<string[]>([])
  const [thumbnail, setThumbnail]   = useState<File | null>(null)
  const [thumbPreview, setThumbPrev]= useState<string | null>(null)
  const [teamId, setTeamId]         = useState<string>('')
  const [myTeams, setMyTeams]       = useState<Array<{ id: string; name: string }>>([])

  useEffect(() => {
    const supabase = createClient()
    supabase.auth.getUser().then(({ data: { user } }) => {
      if (!user) { window.location.href = '/login'; return }
      setUserId(user.id)
      // Load tags
      supabase.from('tags').select('*').order('name').then(({ data }) => setTags((data as Tag[]) ?? []))
      // Load user's teams (leader only)
      supabase.from('team_members').select('team_id, role, teams(id, name)')
        .eq('profile_id', user.id).eq('role', 'leader')
        .then(({ data }) => {
          setMyTeams((data as any[])?.map(m => m.teams).filter(Boolean) ?? [])
        })
    })
  }, [])

  function handleThumbChange(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return
    if (file.size > 5 * 1024 * 1024) { showToast('Image must be under 5MB', 'error'); return }
    setThumbnail(file)
    setThumbPrev(URL.createObjectURL(file))
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (!title.trim()) { showToast('Project title is required', 'error'); return }
    if (!description.trim()) { showToast('Short description is required', 'error'); return }
    if (!userId) { showToast('You must be signed in', 'error'); return }

    setLoading(true)
    const supabase = createClient()

    // Upload thumbnail if provided
    let thumbnailUrl: string | null = null
    if (thumbnail) {
      const ext  = thumbnail.name.split('.').pop()
      const path = `thumbnails/${userId}-${Date.now()}.${ext}`
      const { error: upErr } = await supabase.storage
        .from('project-thumbnails')
        .upload(path, thumbnail, { upsert: true })
      if (upErr) { showToast('Thumbnail upload failed', 'error'); setLoading(false); return }
      const { data: urlData } = supabase.storage.from('project-thumbnails').getPublicUrl(path)
      thumbnailUrl = urlData.publicUrl
    }

    // Insert project
    const { data: project, error: projErr } = await supabase
      .from('projects')
      .insert({
        title: title.trim(),
        description: description.trim(),
        long_description: longDesc.trim() || null,
        thumbnail_url: thumbnailUrl,
        repo_url: repoUrl.trim() || null,
        live_url: liveUrl.trim() || null,
        demo_url: demoUrl.trim() || null,
        submitted_by: userId,
        team_id: teamId || null,
        academic_year: year || null,
        semester: semester || null,
        status: 'approved',
      })
      .select()
      .single()

    if (projErr || !project) {
      showToast('Failed to submit project', 'error')
      setLoading(false)
      return
    }

    const pid = project.id

    // Insert tags
    if (selectedTags.length > 0) {
      await supabase.from('project_tags').insert(
        selectedTags.map(tagId => ({ project_id: pid, tag_id: tagId }))
      )
    }

    // Insert owner as project_member
    await supabase.from('project_members').insert({ project_id: pid, profile_id: userId, role: 'owner' })

    // Insert build-ons
    if (buildOns.length > 0) {
      await supabase.from('build_ons').insert(
        buildOns.map(parentId => ({ parent_project_id: parentId, child_project_id: pid }))
      )
    }

    showToast('Project submitted!', 'success')
    window.location.href = `/projects/${pid}`
  }

  const fieldLabel: React.CSSProperties = {
    display: 'block', fontSize: 12, fontWeight: 500,
    color: 'var(--text-secondary)', marginBottom: 6,
    letterSpacing: '0.05em', textTransform: 'uppercase',
  }
  const input: React.CSSProperties = { width: '100%', padding: '11px 14px', borderRadius: 10 }
  const section: React.CSSProperties = {
    background: 'var(--bg-surface)',
    border: '1px solid var(--border-subtle)',
    borderRadius: 16, padding: '28px',
    marginBottom: 24,
  }

  return (
    <div style={{ maxWidth: 760, margin: '0 auto', padding: '48px 40px 80px' }}>
      <div className="animate-fade-up" style={{ marginBottom: 40 }}>
        <h1 style={{
          fontFamily: 'Cormorant Garamond, serif',
          fontSize: 56, fontWeight: 400, lineHeight: 1,
          color: 'var(--text-primary)', marginBottom: 10,
        }}>
          Submit Project
        </h1>
        <p style={{ fontSize: 14, color: 'var(--text-muted)', fontWeight: 300 }}>
          Your work will be permanently visible to all ITM University students.
        </p>
      </div>

      <form onSubmit={handleSubmit}>

        {/* Basic Info */}
        <div className="animate-fade-up delay-1" style={section}>
          <h2 style={{ fontFamily: 'Cormorant Garamond, serif', fontSize: 22, marginBottom: 20 }}>
            Basic Info
          </h2>
          <div style={{ marginBottom: 16 }}>
            <label style={fieldLabel}>Project Title <span style={{ color: 'var(--accent)' }}>*</span></label>
            <input value={title} onChange={e => setTitle(e.target.value)}
              placeholder="My Awesome Project" style={input} />
          </div>
          <div style={{ marginBottom: 16 }}>
            <label style={fieldLabel}>Short Description <span style={{ color: 'var(--accent)' }}>*</span></label>
            <textarea value={description} onChange={e => setDesc(e.target.value)}
              placeholder="What does this project do? (1-2 sentences)" rows={3}
              style={{ ...input, resize: 'vertical' }} />
          </div>
          <div>
            <label style={fieldLabel}>Full Description / README</label>
            <textarea value={longDesc} onChange={e => setLongDesc(e.target.value)}
              placeholder="Detailed explanation, how it works, what you learned..." rows={8}
              style={{ ...input, resize: 'vertical', fontFamily: 'monospace', fontSize: 13 }} />
          </div>
        </div>

        {/* Thumbnail */}
        <div className="animate-fade-up delay-2" style={section}>
          <h2 style={{ fontFamily: 'Cormorant Garamond, serif', fontSize: 22, marginBottom: 20 }}>
            Thumbnail
          </h2>
          {thumbPreview && (
            <div style={{
              width: '100%', height: 200, borderRadius: 12,
              overflow: 'hidden', marginBottom: 16, border: '1px solid var(--border-subtle)',
            }}>
              <img src={thumbPreview} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="Preview" />
            </div>
          )}
          <label style={{
            display: 'block', padding: '32px',
            border: '2px dashed var(--border)',
            borderRadius: 12, textAlign: 'center',
            cursor: 'pointer', transition: 'border-color 0.2s',
          }}>
            <input type="file" accept="image/*" onChange={handleThumbChange} style={{ display: 'none' }} />
            <div style={{ fontSize: 28, marginBottom: 8, opacity: 0.5 }}>◫</div>
            <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>
              Click to upload thumbnail (JPG, PNG, max 5MB)
            </div>
          </label>
        </div>

        {/* Links */}
        <div className="animate-fade-up delay-2" style={section}>
          <h2 style={{ fontFamily: 'Cormorant Garamond, serif', fontSize: 22, marginBottom: 20 }}>
            Links
          </h2>
          <div style={{ display: 'grid', gap: 14 }}>
            {[
              { label: 'GitHub Repository', val: repoUrl, set: setRepoUrl, placeholder: 'https://github.com/...' },
              { label: 'Live URL', val: liveUrl, set: setLiveUrl, placeholder: 'https://myproject.vercel.app' },
              { label: 'Demo Video', val: demoUrl, set: setDemoUrl, placeholder: 'https://youtube.com/...' },
            ].map(({ label, val, set, placeholder }) => (
              <div key={label}>
                <label style={fieldLabel}>{label}</label>
                <input value={val} onChange={e => set(e.target.value)} placeholder={placeholder} style={input} />
              </div>
            ))}
          </div>
        </div>

        {/* Academic Info */}
        <div className="animate-fade-up delay-3" style={section}>
          <h2 style={{ fontFamily: 'Cormorant Garamond, serif', fontSize: 22, marginBottom: 20 }}>
            Academic Info
          </h2>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
            <div>
              <label style={fieldLabel}>Semester</label>
              <select value={semester} onChange={e => setSemester(e.target.value)} style={{ ...input, cursor: 'pointer' }}>
                <option value="">Select semester</option>
                {SEMESTERS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <label style={fieldLabel}>Academic Year</label>
              <select value={year} onChange={e => setYear(e.target.value)} style={{ ...input, cursor: 'pointer' }}>
                <option value="">Select year</option>
                {YEARS.map(y => <option key={y} value={y}>{y}</option>)}
              </select>
            </div>
          </div>
          {myTeams.length > 0 && (
            <div style={{ marginTop: 16 }}>
              <label style={fieldLabel}>Team (optional)</label>
              <select value={teamId} onChange={e => setTeamId(e.target.value)} style={{ ...input, cursor: 'pointer' }}>
                <option value="">Individual submission</option>
                {myTeams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
              </select>
            </div>
          )}
        </div>

        {/* Tags */}
        <div className="animate-fade-up delay-3" style={section}>
          <h2 style={{ fontFamily: 'Cormorant Garamond, serif', fontSize: 22, marginBottom: 20 }}>
            Tags
          </h2>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            {tags.map(tag => (
              <button key={tag.id} type="button"
                onClick={() => setSelTags(prev =>
                  prev.includes(tag.id) ? prev.filter(x => x !== tag.id) : [...prev, tag.id]
                )}
                className={`tag-pill ${selectedTags.includes(tag.id) ? 'active' : ''}`}
                style={{ cursor: 'pointer', border: 'none', fontFamily: 'inherit' }}
              >
                {tag.name}
              </button>
            ))}
          </div>
        </div>

        {/* Build-ons */}
        <div className="animate-fade-up delay-4" style={section}>
          <h2 style={{ fontFamily: 'Cormorant Garamond, serif', fontSize: 22, marginBottom: 8 }}>
            Build-on
          </h2>
          <p style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 16 }}>
            Does this project extend or build on top of an existing project? Credit them here.
          </p>
          <BuildOnSelector
            selectedIds={buildOns}
            onChange={setBuildOns}
          />
        </div>

        {/* Submit */}
        <button type="submit" disabled={loading} style={{
          width: '100%', padding: '16px',
          background: loading ? 'var(--border)' : 'var(--accent)',
          color: loading ? 'var(--text-muted)' : '#1c1917',
          border: 'none', borderRadius: 12,
          fontSize: 15, fontWeight: 600,
          cursor: loading ? 'not-allowed' : 'pointer',
          fontFamily: 'inherit', letterSpacing: '0.02em',
          transition: 'all 0.2s',
        }}>
          {loading ? 'Submitting…' : 'Submit Project →'}
        </button>
      </form>
    </div>
  )
}
